local LGpBaseMgr = LxRequire("LApp.gameplay.Base.LGpBaseMgr")
---@class LStoryManager: LGpBaseMgr
local LStoryManager = LxClass("LStoryManager", LGpBaseMgr)

LXImport(".LStoryConst")

local typeMapBTIdleController = typeof(CardEHT.MapBTIdleController)
local LStoryObjectCtrl = LXImport(".Ctrl.LStoryObjectCtrl")
local LFightIdleAreaCtrl = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdleAreaCtrl")
local LFightIdlePathCtrl = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdlePathCtrl")
local LFightIdleEffectCtrl = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdleEffectCtrl")
local LFightIdleHudCtrl = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdleHudCtrl")
