function LStoryManager:LStoryManager()

    ---@type LStoryObjectCtrl
    self._objCtrl =nil

    ---@type LStoryEventCtrl
    self._eventCtrl = nil
end

function LStoryManager:Create()

    return LGpBaseMgr.Create(self)
end

function LStoryManager:StartStory(storyId,isClean,plotGamePara)

    -- if plotGamePara then
    --     self._plotGamePara = plotGamePara
    -- end

    self._isRunning = true
    gModelGeneral:SetInStory(true)

    gModelGeneral:SetFirstStory(storyId)

    self._storyId = storyId

    self:SetUIVisible(false)
    self:ParseConfig()

    local cfg = gModelPlot:GetStorySceneRef(storyId)
    if not cfg then
        printErrorN("not storyscene cfg id "..storyId)
        return
    end
    gModelPlot:OnSceneSystemLookReq(storyId)
    self._storySceneType = cfg.type
    local mapName = cfg.storyScene
    if not string.isempty(mapName) then
        self:ChangeMap(mapName,true)
    else
        if self._isInit then
            self:StopIdleRun()
            if isClean then
                self._eventCtrl:ClearAllEvent()
            end

            self._eventCtrl:InitStoryEvent(storyId)
            self:StartIdleRun()
        end

    end

    self:RemoveTouchEvent()
    self:InitTouchEvent()

end

function LStoryManager:ChangeMap(mapName,clearEvent)
    self:Clear(not clearEvent)
    local mapRefId = mapName.."Ref"
    local idleMapRef = GameTable[mapRefId]
    self._curMapIdleRef = idleMapRef
    self._moveType = idleMapRef.moveType
    self._moveDistance = idleMapRef.moveDistance

    self:InitCtrl()

    GF.ChangeMap("LStoryMap",false,{mapName = mapName,isFromStory = true})
end


function LStoryManager:OnMapLoaded(mapTrans)

    gModelGeneral:SetInStory(true)
    self._mapTrans = mapTrans

    self:InitRootNode()
    self:PrepareCameraSetting()
    self:InitCtrlAfterMap()
end

function LStoryManager:ParseConfig()
    local str = gModelInstance:GetInstancePara("HeroAttDisOnHook")
    self._cfgVHeroAttDisOnHookMap = LxDataHelper.ParseIntKVList_Semicolon(str or "")

    -----------------------------------------------------------------
    str = gModelInstance:GetInstancePara("CameraMoveXY")
    local arrCameraMoveXYStr = LxDataHelper.ParseStringParam_Semicolon(str or "")-- [[0.9;1.1]]
    local cameraMoveX = tonumber(arrCameraMoveXYStr[1]) or 0
    local cameraMoveY = tonumber(arrCameraMoveXYStr[2]) or 0
    self._cfgVCameraFollowOffset = Vector3(cameraMoveX * 0.01,cameraMoveY * 0.01,0)
    str = gModelInstance:GetInstancePara("CameraMoveR")
    self._cfgVCameraFollowRange = (str or 0) * 0.01
end

function LStoryManager:InitRootNode()
    local mapTrans = self._mapTrans

    local layerRoot = CS.FindTrans(mapTrans,"LayerRoot")
    self._layerRootTrans = layerRoot

    self._boardRootTrans = CS.FindTrans(layerRoot,"LayerBoard")

    local layerTrans = nil

    layerTrans = CS.FindTrans(layerRoot,"LayerObject")
    if not layerTrans then
        layerTrans = CS.NewObject("LayerObject",layerRoot)
    end
    self._objRootTrans = layerTrans

    layerTrans = CS.FindTrans(layerRoot,"LayerEffect")
    if not layerTrans then
        layerTrans = CS.NewObject("LayerEffect",layerRoot)
    end
    self._effectRootTrans = layerTrans

    layerTrans = CS.FindTrans(layerRoot,"LayerPool")
    if not layerTrans then
        layerTrans = CS.NewObject("LayerPool",layerRoot)
    end
    self._dropPoolTrans = layerTrans

    self._btIdleController = self._layerRootTrans:GetComponent(typeMapBTIdleController)

end

function LStoryManager:PrepareCameraSetting()
    self._btIdleController:ResetAll()
    local pixelPos = self._curMapIdleRef.initPos
    local initCameraPos = LUtil.ConvertPixelPosToUnitPos(pixelPos)
    self:SetCameraPos(initCameraPos)

    if self._moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL then
        self._lastMaxPos = initCameraPos.x
    else
        self._lastMaxPos = initCameraPos.y
    end
    self._currentLeaderPos = initCameraPos
end

function LStoryManager:StartIdleRun()
    self:StopIdleRun()
    self._loopTimer = LxTimer.LoopTimeCall(function()
        self:OnIdleRun()
    end,0,false,-1)
end

function LStoryManager:StopIdleRun()
    if not self._loopTimer  then return end
    LxTimer.LoopTimeStop(self._loopTimer)
    self._loopTimer  = nil
end

function LStoryManager:OnIdleRun()
    local time = self:GetTime()
    self._objCtrl:OnRun(time)
    self._effCtrl:OnRun(time)
    self._hudCtrl:OnRun(time)

    self._eventCtrl:OnRun(time)
end

function LStoryManager:GetTime()
    if self._time then
        return self._time
    else
        return Time.time+ (self._timeDif or 0)
    end
end

function LStoryManager:Pause()
    if not self:IsRunning() then
        return
    end
    local time = self:GetTime()
    self._time = time

    self._objCtrl:TimePause()
    self._effCtrl:TimePause()
    if self._btIdleController then
        self._btIdleController:TimePause()
    end
end

function LStoryManager:Resume()
    local time = self._time or Time.time
    local timeDif =time - Time.time
    self._timeDif = timeDif
    self._time = nil

    self._objCtrl:TimeResume()
    self._effCtrl:TimeResume()
    if self._btIdleController then
        self._btIdleController:TimeResume()
    end
end

function LStoryManager:InitCtrlAfterMap()
    local areaCtrl = self._areaCtrl
    local boardsRoot = self:GetBoardRootTrans()
    areaCtrl:InitArea(self._curMapIdleRef,self._moveDistance * 0.01,self._moveType,boardsRoot)
    areaCtrl:ShowAllArea()


    self:StartIdleRun() --开始剧情帧循环
end

function LStoryManager:GetBoardRootTrans()
    return self._boardRootTrans
end

function LStoryManager:InitCtrl()
    self._objCtrl = LStoryObjectCtrl:New(self)

    local heroAttackSpeed =gModelInstance:GetInstancePara("HeroAttackSpeed")
    local moveSpeed =gModelInstance:GetInstancePara("HeroMoveSpeed")
    local heroSizeOnHook =gModelInstance:GetInstancePara("HeroSizeOnHook")
    local jumpCD =gModelInstance:GetInstancePara("JumpCD")
    -- local heroAttSpeedUp =gModelInstance:GetInstancePara("HeroAttSpeedUp")
    local heroAttSpeedUp =gModelInstance:GetHeroAttSpeedUp()

    self._cfgMonHitByHand = gModelInstance:GetInstancePara("MonHitByHand")
    self._cfgMonHitEffect = gModelInstance:GetInstancePara("MonHitEffect")

    self._objCtrl:InitHeroData(heroAttackSpeed,moveSpeed,heroSizeOnHook,self._cfgVHeroAttDisOnHookMap,jumpCD,heroAttSpeedUp)
    self._objCtrl:InitGodSkillData(self._cfgMonHitEffect, self._cfgMonHitByHand)

    self._areaCtrl = LFightIdleAreaCtrl:New()

    self._pathCtrl = LFightIdlePathCtrl:New()
    local idleMapRef = self._curMapIdleRef
    self._pathCtrl:InitPath(idleMapRef.links,idleMapRef.boards)

    self._effCtrl = LFightIdleEffectCtrl:New(self)

    self._hudCtrl = LFightIdleHudCtrl:New(self)
    self._hudCtrl:InitHud()


    self._hurtCtrl = LStoryHurtCtrl:New(self)
    self._hurtCtrl:InitFloat()



    if not self._eventCtrl then
        self._eventCtrl = LStoryEventCtrl:New(self)
        self._eventCtrl:InitStoryEvent(self._storyId)
    end

    self._isInit = true

end



