function LStoryManager:Clear(keepEventCtrl)
    self:StopMoveCamera()

    self._btIdleController = nil

    self:StopIdleRun()

    if self._eventCtrl and not keepEventCtrl then
        --self._eventCtrl:ClearAllEvent()
        self._eventCtrl:Destroy()
        self._eventCtrl = nil
    end

    if(self._effCtrl) then
        self._effCtrl:Destroy()
        self._effCtrl = nil
    end
    if(self._objCtrl) then
        self._objCtrl:Destroy()
        self._objCtrl = nil
    end
    if(self._areaCtrl) then
        self._areaCtrl:Destroy()
        self._areaCtrl = nil
    end
    if(self._pathCtrl) then
        self._pathCtrl:Destroy()
        self._pathCtrl = nil
    end
    if (self._hudCtrl) then
        self._hudCtrl:Destroy()
        self._hudCtrl = nil
    end

    if self._hurtCtrl then
        self._hurtCtrl:Destroy()
        self._hurtCtrl = nil
    end

    GF.CloseWndByName("UISy")

    self._isInit = false
end

function LStoryManager:InitTouchEvent()
    local op = LGameTouch.TOUCH_STORY
    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_START,function (screenPos)
        local pos = gLGameScene:GetCurrentSceneCamera():ScreenToWorldPoint(screenPos)
        self._objCtrl:OnTouchStart(pos)
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_MOVE,function (screenPos)
        local pos = gLGameScene:GetCurrentSceneCamera():ScreenToWorldPoint(screenPos)
        self._objCtrl:OnTouchMove(pos)
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_END,function (screenPos)
        local pos = gLGameScene:GetCurrentSceneCamera():ScreenToWorldPoint(screenPos)
        self._objCtrl:OnTouchEnd(pos)
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_CANCEL,function (screenPos)
        self._objCtrl:OnTouchCancel()
    end)
end

function LStoryManager:RemoveTouchEvent()
    if gLGameTouch then gLGameTouch:TouchUnRegister(LGameTouch.TOUCH_STORY) end
end

